16	void paillier_gen_interactive_t::step1_p1_to_p2(crypto::paillier_t& paillier, const bn_t& x1, const mod_t& q,
17	                                                bn_t& c_key) {
18	  if (!paillier.has_private_key()) paillier.generate();
19	  const mod_t& N = paillier.get_N();
20	  cb_assert(N > ((q * q * q) << (3 * SEC_P_STAT + SEC_P_COM + 1)));
21	  this->N = N;
22	
23	  r_key = bn_t::rand(N);
24	  this->c_key = c_key = paillier.encrypt(x1, r_key);
25	
26	  const zk::pedersen_commitment_params_t& params = zk::pedersen_commitment_params_t::get();
27	  const mod_t& p_tag = params.p_tag;
28	  const mod_t& p = params.p;
29	  const bn_t& g = params.g;
30	  const bn_t& h = params.h;
31	
32	  rho = bn_t::rand(p_tag);
33	  MODULO(p) Com = g.pow(x1) * h.pow(rho);
34	
35	  equal.prover_msg1(paillier, q);
36	  range.prover_msg1(q);
37	}
