54	error_t paillier_gen_interactive_t::step4_p2_output(crypto::paillier_t& paillier, const ecc_point_t& Q1,
55	                                                    const bn_t& c_key, const crypto::mpc_pid_t& prover_pid, mem_t sid) {
56	  error_t rv = UNINITIALIZED_ERROR;
57	  ecurve_t curve = Q1.get_curve();
58	  const mod_t& q = curve.order();
59	  const int N_bits = N.get_bits_count();
60	  if (N_bits < crypto::paillier_t::bit_size) return coinbase::error(E_CRYPTO);
61	  if (N_bits > crypto::paillier_t::bit_size)
62	    return coinbase::error(E_CRYPTO, "unsupported Paillier modulus size from counterparty");
63	  if (N_bits < 3 * q.get_bits_count() + 3 * SEC_P_STAT + SEC_P_COM + 1)
64	    return coinbase::error(E_CRYPTO, "length of N < 3lg q+ 3 stat-sec-param + com-sec-param + 1");
65	  if (rv = paillier.create_pub(N)) return coinbase::error(E_CRYPTO, "invalid Paillier modulus from counterparty");
66	
67	  // Potential optimization: both `verify_cipher` and pdl.verify perform GCDs. These can be merged into a single GCD by
68	  // multiplying them together. See the notes in the spec.
69	  if (rv = paillier.verify_cipher(c_key)) return rv;
70	
71	  if (rv = valid.verify(paillier, prover_pid, valid_m2)) return rv;
72	
73	  pdl.paillier_valid_key = valid.paillier_valid_key;
74	  pdl.paillier_no_small_factors = valid.paillier_no_small_factors;
75	  pdl.paillier_range_exp_slack_proof = zk::zk_flag::skip;
76	  if (rv = pdl.verify(c_key, paillier, Q1, sid, 0)) return rv;
77	
78	  equal.paillier_valid_key = valid.paillier_valid_key;
79	  equal.paillier_no_small_factors = valid.paillier_no_small_factors;
80	  if (rv = equal.verify(paillier, c_key, q, Com)) return rv;
81	  if (rv = range.verify(Com, q)) return rv;
82	  return SUCCESS;
83	}
