411	error_t sign(job_2p_t& job, buf_t& sid, const key_t& key, const mem_t msg, buf_t& sig) {
412	  error_t rv = UNINITIALIZED_ERROR;
413	  std::vector<mem_t> msgs(1, msg);
414	  std::vector<buf_t> sigs;
415	  if (rv = sign_batch(job, sid, key, msgs, sigs)) return rv;
416	  sig = sigs[0];
417	  return SUCCESS;
418	}
