14	error_t key_share_ecdsa_hdmpc_2p_t::dkg(job_2p_t& job, ecurve_t curve, key_share_ecdsa_hdmpc_2p_t& key) {
15	  error_t rv = UNINITIALIZED_ERROR;
16	
17	  key.curve = curve;
18	  const mod_t& q = curve.order();
19	
20	  key.root.x_share = bn_t::rand(q);
21	  key.root.k_share = bn_t::rand(q);
22	  key.party_index = job.get_party_idx();
23	
24	  const crypto::mpc_pid_t& p1_pid = job.get_pid(party_t::p1);
25	  ecdsa2pc::paillier_gen_interactive_t pg(p1_pid);
26	  eckey::dkg_2p_t x_dkg(curve, p1_pid), k_dkg(curve, p1_pid);
27	
28	  if (job.is_p1()) {
29	    x_dkg.step1_p1_to_p2(key.root.x_share);
30	    k_dkg.step1_p1_to_p2(key.root.k_share);
31	    pg.step1_p1_to_p2(key.paillier, key.root.x_share, x_dkg.curve.order(), key.c_key);
32	  }
33	
34	  if (rv = job.p1_to_p2(x_dkg.msg1, k_dkg.msg1, pg.msg1)) return rv;
35	
36	  if (job.is_p2()) {
37	    x_dkg.step2_p2_to_p1(key.root.x_share);
38	    k_dkg.step2_p2_to_p1(key.root.k_share);
39	    pg.step2_p2_to_p1();
40	  }
41	
42	  if (rv = job.p2_to_p1(x_dkg.msg2, k_dkg.msg2, pg.msg2)) return rv;
43	
44	  if (job.is_p1()) {
45	    if (rv = x_dkg.step3_p1_to_p2(key.root.Q)) return rv;
46	    if (rv = k_dkg.step3_p1_to_p2(key.root.K)) return rv;
47	    pg.step3_p1_to_p2(key.paillier, key.root.x_share, x_dkg.Q1, job.get_pid(party_t::p1), x_dkg.sid);
48	  }
49	
50	  if (rv = job.p1_to_p2(x_dkg.msg3, k_dkg.msg3, pg.msg3)) return rv;
51	
52	  if (job.is_p2()) {
53	    if (rv = x_dkg.step4_output_p2(key.root.Q)) return rv;
54	    if (rv = k_dkg.step4_output_p2(key.root.K)) return rv;
55	    key.c_key = pg.c_key;
56	    if (rv = pg.step4_p2_output(key.paillier, x_dkg.Q1, key.c_key, job.get_pid(party_t::p1), x_dkg.sid)) return rv;
57	  }
58	
59	  return SUCCESS;
60	}
