62	error_t key_share_ecdsa_hdmpc_2p_t::refresh(job_2p_t& job, key_share_ecdsa_hdmpc_2p_t& key,
63	                                            key_share_ecdsa_hdmpc_2p_t& new_key) {
64	  // NOTE: this is not an optimized version of the refresh function and has twice as many rounds as needed since
65	  //       the refresh operations are performed sequentially. It can be made more optimized by copy-pasting the
66	  //       two refresh code and interleaving the operations.
67	  //       We are using this less optimized version for simplicity.
68	  error_t rv = UNINITIALIZED_ERROR;
69	  ecdsa2pc::key_t ecdsa_key =
70	      ecdsa2pc::key_t{party_t(key.party_index), key.curve, key.root.Q, key.root.x_share, key.c_key, key.paillier};
71	  eckey::key_share_2p_t root_key =
72	      eckey::key_share_2p_t{party_t(key.party_index), key.curve, key.root.K, key.root.k_share};
73	
74	  ecdsa2pc::key_t new_ecdsa_key;
75	  eckey::key_share_2p_t new_root_key;
76	
77	  if (rv = ecdsa2pc::refresh(job, ecdsa_key, new_ecdsa_key)) return rv;
78	  if (rv = root_key.refresh(job, root_key, new_root_key)) return rv;
79	
80	  new_key.party_index = key.party_index;
81	  new_key.curve = key.curve;
82	
83	  new_key.root.Q = new_ecdsa_key.Q;
84	  new_key.root.x_share = new_ecdsa_key.x_share;
85	  new_key.c_key = new_ecdsa_key.c_key;
86	  new_key.paillier = new_ecdsa_key.paillier;
87	
88	  new_key.root.k_share = new_root_key.x_share;
89	  new_key.root.K = new_root_key.Q;
90	
91	  return SUCCESS;
92	}
