183	error_t get_public_key_compressed(mem_t key_blob, buf_t& pub_key) {
184	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(key_blob, "key_blob",
185	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
186	    return rv;
187	  coinbase::mpc::ecdsa2pc::key_t key;
188	  const error_t rv = deserialize_key_blob(key_blob, key);
