194	error_t get_public_share_compressed(mem_t key_blob, buf_t& out_public_share_compressed) {
195	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(key_blob, "key_blob",
196	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
197	    return rv;
198	  coinbase::mpc::ecdsa2pc::key_t key;
199	  error_t rv = deserialize_key_blob(key_blob, key);
200	  if (rv) return rv;
201	
202	  const auto& q = key.curve.order();
203	  const coinbase::crypto::bn_t x_mod_q = key.x_share % q;
204	  out_public_share_compressed = (x_mod_q * key.curve.generator()).to_compressed_bin();
205	  return SUCCESS;
206	}
