208	error_t detach_private_scalar(mem_t key_blob, buf_t& out_public_key_blob, buf_t& out_private_scalar) {
209	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(key_blob, "key_blob",
210	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
211	    return rv;
212	  coinbase::mpc::ecdsa2pc::key_t key;
213	  error_t rv = deserialize_key_blob(key_blob, key);
214	  if (rv) return rv;
215	
216	  curve_id cid;
217	  if (!from_internal_curve(key.curve, cid)) return coinbase::error(E_BADARG, "unsupported curve");
218	  if (cid == curve_id::ed25519) return coinbase::error(E_BADARG, "unsupported curve");
219	
220	  // Variable-length big-endian encoding (may grow after refresh).
221	  out_private_scalar = key.x_share.to_bin();
222	
223	  // Produce a v1-format blob with an invalid (out-of-range) scalar share so it is
224	  // rejected by sign/refresh APIs.
225	  key_blob_v1_t pub;
226	  pub.role = static_cast<uint32_t>(key.role);
227	  pub.curve = static_cast<uint32_t>(cid);
228	  pub.Q_compressed = key.Q.to_compressed_bin();
229	  pub.x_share = key.paillier.get_N().value();  // x_share == N is out of range
230	  pub.c_key = key.c_key;
231	  pub.paillier = key.paillier;
232	  out_public_key_blob = coinbase::convert(pub);
233	  return SUCCESS;
234	}
