236	error_t attach_private_scalar(mem_t public_key_blob, mem_t private_scalar, mem_t public_share_compressed,
237	                              buf_t& out_key_blob) {
238	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(public_key_blob, "public_key_blob",
239	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
240	    return rv;
241	  key_blob_v1_t pub;
242	  error_t rv = coinbase::convert(pub, public_key_blob);
243	  if (rv) return rv;
244	  if (pub.version != key_blob_version_v1) return coinbase::error(E_FORMAT, "unsupported key blob version");
245	  if (pub.role > 1) return coinbase::error(E_FORMAT, "invalid key blob role");
246	
247	  const auto cid = static_cast<curve_id>(pub.curve);
248	  if (cid == curve_id::ed25519) return coinbase::error(E_FORMAT, "invalid key blob curve");
249	  auto curve = to_internal_curve(cid);
250	  if (!curve.valid()) return coinbase::error(E_FORMAT, "invalid key blob curve");
251	
252	  if (const error_t rvm = coinbase::api::detail::validate_mem_arg(private_scalar, "private_scalar")) return rvm;
253	  if (private_scalar.size == 0) return coinbase::error(E_BADARG, "private_scalar must be non-empty");
254	  if (const error_t rvp = coinbase::api::detail::validate_mem_arg(public_share_compressed, "public_share_compressed"))
255	    return rvp;
256	
257	  // Validate Paillier material (c_key + key) is well-formed.
258	  const bool paillier_has_private = pub.paillier.has_private_key();
259	  if ((pub.role == 0) != paillier_has_private) return coinbase::error(E_FORMAT, "invalid key blob");
260	
261	  const auto& N = pub.paillier.get_N();
262	  if (N.value().get_bits_count() < coinbase::crypto::paillier_t::bit_size)
263	    return coinbase::error(E_FORMAT, "invalid key blob");
264	  {
265	    coinbase::crypto::vartime_scope_t vartime_scope;
266	    if (pub.paillier.verify_cipher(pub.c_key)) return coinbase::error(E_FORMAT, "invalid key blob");
267	  }
268	
269	  // Interpret scalar and ensure it stays in Z_N (matching key blob invariants).
270	  coinbase::crypto::bn_t x_share = coinbase::crypto::bn_t::from_bin(private_scalar);
271	  if (!N.is_in_range(x_share)) return coinbase::error(E_FORMAT, "invalid private_scalar");
272	
273	  // If we have the private key (P1), bind the share to its Paillier encryption.
274	  if (paillier_has_private) {
275	    coinbase::crypto::vartime_scope_t vartime_scope;
276	    const coinbase::crypto::bn_t plain = pub.paillier.decrypt(pub.c_key);
277	    if (plain != N.mod(x_share)) return coinbase::error(E_FORMAT, "x_share mismatch key blob");
278	  }
279	
280	  // Verify scalar matches the provided self-share point.
281	  const coinbase::crypto::mod_t& q = curve.order();
282	  const coinbase::crypto::bn_t x_mod_q = x_share % q;
283	  if (!q.is_in_range(x_mod_q)) return coinbase::error(E_FORMAT, "invalid private_scalar");
284	
285	  coinbase::crypto::ecc_point_t Qi_self(curve);
286	  if (rv = Qi_self.from_bin(curve, public_share_compressed))
287	    return coinbase::error(rv, "invalid public_share_compressed");
288	  if (rv = curve.check(Qi_self)) return coinbase::error(rv, "invalid public_share_compressed");
289	  if (x_mod_q * curve.generator() != Qi_self) return coinbase::error(E_FORMAT, "x_share mismatch key blob");
290	
291	  // Validate and normalize global public key encoding.
292	  coinbase::crypto::ecc_point_t Q(curve);
293	  if (rv = Q.from_bin(curve, pub.Q_compressed)) return coinbase::error(rv, "invalid key blob");
294	  if (rv = curve.check(Q)) return coinbase::error(rv, "invalid key blob");
295	
296	  pub.Q_compressed = Q.to_compressed_bin();
297	  pub.x_share = std::move(x_share);
298	  out_key_blob = coinbase::convert(pub);
299	  return SUCCESS;
300	}
