57	struct keyset_blob_v1_t {
58	  uint32_t version = keyset_blob_version_v1;
59	  uint32_t role = 0;   // 0=p1, 1=p2
60	  uint32_t curve = 0;  // coinbase::api::curve_id
61	
62	  buf_t root_Q_compressed;
63	  buf_t root_K_compressed;
64	  coinbase::crypto::bn_t x_share;
65	  coinbase::crypto::bn_t k_share;
66	  coinbase::crypto::paillier_t paillier;
67	  coinbase::crypto::bn_t c_key;
68	
69	  void convert(coinbase::converter_t& c) {
70	    c.convert(version, role, curve, root_Q_compressed, root_K_compressed, x_share, k_share, paillier, c_key);
71	  }
