74	static error_t blob_to_keyset(const keyset_blob_v1_t& blob, coinbase::mpc::key_share_ecdsa_hdmpc_2p_t& keyset) {
75	  if (blob.role > 1) return coinbase::error(E_FORMAT, "invalid keyset blob role");
76	
77	  const auto cid = static_cast<curve_id>(blob.curve);
78	  if (cid == curve_id::ed25519) return coinbase::error(E_FORMAT, "invalid keyset blob curve");
79	  const auto icurve = to_internal_curve(cid);
80	  if (!icurve.valid()) return coinbase::error(E_FORMAT, "invalid keyset blob curve");
81	
82	  keyset.party_index = static_cast<coinbase::mpc::party_idx_t>(blob.role);
83	  keyset.curve = icurve;
84	
85	  const coinbase::crypto::mod_t& q = keyset.curve.order();
86	  if (!q.is_in_range(blob.k_share)) return coinbase::error(E_FORMAT, "invalid keyset blob");
87	
88	  keyset.root.x_share = blob.x_share;
89	  keyset.root.k_share = blob.k_share;
90	  keyset.paillier = blob.paillier;
91	  keyset.c_key = blob.c_key;
92	
93	  // For ECDSA-2PC, party p1 maintains `x_share` as an integer representative compatible with Paillier plaintext
94	  // operations (it is intentionally not reduced modulo q after refresh). Enforce only that it fits in Z_N.
95	  const coinbase::crypto::mod_t& N = keyset.paillier.get_N();
96	  if (!N.is_in_range(blob.x_share)) return coinbase::error(E_FORMAT, "invalid keyset blob");
97	
98	  error_t rv = keyset.root.Q.from_bin(icurve, blob.root_Q_compressed);
99	  if (rv) return rv;
100	  return keyset.root.K.from_bin(icurve, blob.root_K_compressed);
101	}
