168	error_t derive_ecdsa_2p_keys(const coinbase::api::job_2p_t& job, mem_t keyset_blob, const bip32_path_t& hardened_path,
169	                             const std::vector<bip32_path_t>& non_hardened_paths, buf_t& sid,
170	                             std::vector<buf_t>& out_ecdsa_2p_key_blobs) {
171	  if (const error_t rv = validate_job_2p(job)) return rv;
172	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(keyset_blob, "keyset_blob",
173	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
174	    return rv;
175	  coinbase::mpc::key_share_ecdsa_hdmpc_2p_t keyset;
176	  error_t rv = deserialize_keyset_blob(keyset_blob, keyset);
177	  if (rv) return rv;
178	
179	  const auto self = to_internal_party(job.self);
180	  if (static_cast<uint32_t>(keyset.party_index) != static_cast<uint32_t>(self))
181	    return coinbase::error(E_BADARG, "job.self mismatch keyset blob role");
182	
183	  rv = validate_no_duplicate_bip32_paths(non_hardened_paths);
184	  if (rv) return rv;
185	
186	  coinbase::mpc::job_2p_t mpc_job = to_internal_job(job);
187	
188	  const coinbase::mpc::bip32_path_t hardened_path_internal = to_internal_bip32_path(hardened_path);
189	  std::vector<coinbase::mpc::bip32_path_t> non_hardened_paths_internal;
190	  non_hardened_paths_internal.reserve(non_hardened_paths.size());
191	  for (const auto& p : non_hardened_paths) non_hardened_paths_internal.push_back(to_internal_bip32_path(p));
192	
193	  std::vector<coinbase::mpc::ecdsa2pc::key_t> derived_keys(non_hardened_paths.size());
194	  rv = coinbase::mpc::key_share_ecdsa_hdmpc_2p_t::derive_keys(mpc_job, keyset, hardened_path_internal,
195	                                                              non_hardened_paths_internal, sid, derived_keys);
196	  if (rv) {
197	    out_ecdsa_2p_key_blobs.clear();
198	    return rv;
199	  }
200	
201	  std::vector<buf_t> blobs;
202	  blobs.resize(derived_keys.size());
203	  for (size_t i = 0; i < derived_keys.size(); i++) {
204	    rv = serialize_ecdsa2pc_key_blob(derived_keys[i], blobs[i]);
205	    if (rv) {
206	      out_ecdsa_2p_key_blobs.clear();
207	      return rv;
208	    }
209	  }
210	
211	  out_ecdsa_2p_key_blobs = std::move(blobs);
212	  return SUCCESS;
213	}
