215	error_t extract_root_public_key_compressed(mem_t keyset_blob, buf_t& out_Q_compressed) {
216	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(keyset_blob, "keyset_blob",
217	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
218	    return rv;
219	  coinbase::mpc::key_share_ecdsa_hdmpc_2p_t keyset;
220	  const error_t rv = deserialize_keyset_blob(keyset_blob, keyset);
221	  if (rv) return rv;
222	  out_Q_compressed = keyset.root.Q.to_compressed_bin();
223	  return SUCCESS;
224	}
